const setup = $('⚙️ Setup').first().json;
const orders = ($json.orders || []).filter(o => !o.cancelled_at);
const produkte = {};
for (const o of orders) {
  for (const li of (o.line_items || [])) produkte[li.title] = (produkte[li.title] || 0) + li.quantity;
}
const top = Object.entries(produkte).sort((a, b) => b[1] - a[1]).slice(0, 3).map(([n]) => n);
const topText = top.length ? top.join(', ') : '(noch keine Verkaeufe - nutze die Nische)';

// Taeglich rotierendes Kern-Thema, damit nicht jeden Tag dasselbe kommt
const themen = [
  'Ergebnis/Transformation zeigen',
  'Haeufigster Fehler der Zielgruppe',
  'Produkt im Alltag (POV-Style)',
  'Frage/Debatte starten (Engagement)',
  'Mini-Tutorial mit dem Produkt',
  'Kundenstimme/Review nacherzaehlen',
  'Zahlen/Fakten, die ueberraschen'
];
const thema = themen[new Date().getDay()];

const prompt = 'Du bist Multi-Plattform-Social-Media-Manager fuer den Onlineshop "' + setup.SHOP_NAME + '" (Nische: ' + setup.SHOP_NISCHE + ', Zielgruppe: ' + setup.ZIELGRUPPE + ', Shop: ' + setup.SHOP_URL + ').\n' +
  'Bestseller: ' + topText + '\nKern-Thema heute: ' + thema + '\n\n' +
  'Erstelle das komplette Posting-Paket fuer HEUTE - EIN Kern-Inhalt, fuer jede Plattform nativ uebersetzt (nicht kopiert!), alles auf Deutsch:\n\n' +
  '1. TIKTOK: Hook (max 10 Woerter) + 20-30s Skript (Szene fuer Szene) + 4 Hashtags + Sound-Idee\n' +
  '2. INSTAGRAM REEL: Angepasster Hook + Caption mit CTA + 5 Hashtags\n' +
  '3. INSTAGRAM STORY: 2-Slide-Idee mit Interaktions-Sticker (Umfrage/Slider)\n' +
  '4. FACEBOOK: Laengerer Post (60-100 Woerter, Story-Stil, 1 Emoji-Absatztrenner, Link zum Shop)\n' +
  '5. PINTEREST: Pin-Titel (max 60 Zeichen) + Beschreibung (max 200 Zeichen, SEO-Keywords der Nische)\n' +
  '6. YOUTUBE SHORT: Titel + 25s Skript (kann das TikTok-Skript adaptieren)\n' +
  '7. X/TWITTER: 2 Tweets (einer frech/meinungsstark, einer mit Mehrwert)\n\n' +
  'Antworte NUR mit validem JSON, ohne Markdown-Codeblock:\n' +
  '{"facebook_post": "<nur der reine Facebook-Text>", "html": "<das GESAMTE Paket als sauberes HTML mit h2 pro Plattform, copy-paste-freundlich, ohne html/body-Geruest>"}';

return [{ json: { prompt, thema } }];

const blocks = $json.content || [];
const text = (blocks.find(b => b.type === 'text') || {}).text || '';
let daten;
try {
  daten = JSON.parse(text.replace(/```json|```/g, '').trim());
} catch (e) {
  daten = { facebook_post: '', html: '<pre style="white-space:pre-wrap;font-family:sans-serif;">' + text + '</pre>' };
}
const setup = $('⚙️ Setup').first().json;
const thema = $('🧠 Tages-Thema + Bestseller').item.json.thema;
return { json: {
  betreff: '🌍 Dein Posting-Paket fuer heute (' + thema + ')',
  email_html: '<div style="font-family:sans-serif;max-width:640px;margin:0 auto;">' + daten.html + '</div>',
  facebook_post: daten.facebook_post || '',
  telegram_text: '🌍 MULTI-PLATTFORM-POSTER · ' + setup.SHOP_NAME + '\n\nDein Posting-Paket fuer heute (' + thema + ') liegt im Postfach! 📬\n7 Plattformen, copy-paste-fertig: TikTok, IG Reel + Story, Facebook, Pinterest, YouTube Short, X.' + (setup.AUTO_POST_FACEBOOK === 'ja' && setup.FB_PAGE_ID ? '\n\n🤖 Facebook-Post geht automatisch raus!' : '')
}};

const setup = $('⚙️ Setup').first().json;
const daten = $('📦 Paket verpacken').first().json;
if (setup.AUTO_POST_FACEBOOK !== 'ja') return [];
if (!setup.FB_PAGE_ID || !setup.FB_PAGE_TOKEN) return [];
if (!daten.facebook_post) return [];
return [{ json: { facebook_post: daten.facebook_post } }];
